  1→"use client";
  2→
  3→import { memo, useState, useRef, useCallback } from "react";
  4→import { Position, NodeResizer } from "@xyflow/react";
  5→import type { ResizeParams } from "@xyflow/react";
  6→import { NodeLabel } from "./NodeLabel";
  7→import { ConnectHandle } from "./ConnectHandle";
  8→import { useFlowStore } from "@/store/useFlowStore";
  9→import { computeColor } from "@/lib/color";
 10→import type { TextAlign, TextVerticalAlign } from "@/types/flow";
 11→import { perfCount } from "@/lib/perf";
 12→
 13→interface NodeWrapperProps {
 14→  id: string;
 15→  label: string;
 16→  selected?: boolean;
 17→  className?: string;
 18→  style?: React.CSSProperties;
 19→  fillColor?: string;
 20→  fillOpacity?: number;
 21→  fillLightness?: number;
 22→  borderColor?: string;
 23→  borderOpacity?: number;
 24→  borderLightness?: number;
 25→  borderWidth?: number;
 26→  borderStyle?: string;
 27→  fontSize?: number;
 28→  textColor?: string;
 29→  textOpacity?: number;
 30→  textLightness?: number;
 31→  textAlign?: TextAlign;
 32→  textVerticalAlign?: TextVerticalAlign;
 33→  bold?: boolean;
 34→  italic?: boolean;
 35→  underline?: boolean;
 36→  isLocked?: boolean;
 37→  isComponentChild?: boolean;
 38→  ghostTargetHandle?: string; // e.g. "top-target" — only this handle is rendered (ghost node)
 39→}
 40→
 41→const positions = [Position.Top, Position.Right, Position.Bottom, Position.Left];
 42→
 43→export const NodeWrapper = memo(function NodeWrapper({
 44→  id,
 45→  label,
 46→  selected,
 47→  className = "",
 48→  style,
 49→  fillColor,
 50→  fillOpacity,
 51→  fillLightness,
 52→  borderColor,
 53→  borderOpacity,
 54→  borderLightness,
 55→  borderWidth,
 56→  borderStyle,
 57→  fontSize,
 58→  textColor,
 59→  textOpacity,
 60→  textLightness,
 61→  textAlign,
 62→  textVerticalAlign,
 63→  bold,
 64→  italic,
 65→  underline,
 66→  isLocked,
 67→  isComponentChild,
 68→  ghostTargetHandle,
 69→}: NodeWrapperProps) {
 70→  perfCount("NodeWrapper");
 71→  const [hovered, setHovered] = useState(false);
 72→  const visible = !isComponentChild && hovered;
 73→
 74→  // Multi-node resize: track initial sizes and positions of all selected nodes
 75→  const initialRef = useRef<{ w: number; h: number; x: number; y: number } | null>(null);
 76→  const selectedInitialsRef = useRef<Map<string, { w: number; h: number; x: number; y: number }> | null>(null);
 77→
 78→  const onResizeStart = useCallback(() => {
 79→    const state = useFlowStore.getState();
 80→    const node = state.nodes.find((n) => n.id === id);
 81→    if (node) {
 82→      initialRef.current = {
 83→        w: node.width ?? node.measured?.width ?? (node.style?.width as number) ?? 150,
 84→        h: node.height ?? node.measured?.height ?? (node.style?.height as number) ?? 50,
 85→        x: node.position.x,
 86→        y: node.position.y,
 87→      };
 88→    }
 89→    const initials = new Map<string, { w: number; h: number; x: number; y: number }>();
 90→    for (const n of state.nodes) {
 91→      if (n.selected && n.id !== id && !n.data.componentParentId) {
 92→        initials.set(n.id, {
 93→          w: n.width ?? n.measured?.width ?? (n.style?.width as number) ?? 150,
 94→          h: n.height ?? n.measured?.height ?? (n.style?.height as number) ?? 50,
 95→          x: n.position.x,
 96→          y: n.position.y,
 97→        });
 98→      }
 99→    }
100→    selectedInitialsRef.current = initials;
101→    useFlowStore.temporal.getState().pause();
102→  }, [id]);
103→
104→  const onResize = useCallback((_event: unknown, params: ResizeParams) => {
105→    if (!initialRef.current) return;
106→    const deltaW = params.width - initialRef.current.w;
107→    const deltaH = params.height - initialRef.current.h;
108→    const deltaX = params.x - initialRef.current.x;
109→    const deltaY = params.y - initialRef.current.y;
110→    useFlowStore.getState().resizeSelectedNodes(id, deltaW, deltaH, deltaX, deltaY, selectedInitialsRef.current ?? undefined);
111→  }, [id]);
112→
113→  const onResizeEnd = useCallback(() => {
114→    initialRef.current = null;
115→    selectedInitialsRef.current = null;
116→    useFlowStore.temporal.getState().resume();
117→  }, []);
118→
119→  const colorStyle: React.CSSProperties = {};
120→  const computedFill = computeColor(fillColor, fillOpacity, fillLightness);
121→  const computedBorder = computeColor(borderColor, borderOpacity, borderLightness);
122→  const computedText = computeColor(textColor, textOpacity, textLightness);
123→  if (computedFill !== undefined) colorStyle.backgroundColor = computedFill;
124→  if (computedBorder !== undefined) colorStyle.borderColor = computedBorder;
125→  if (borderWidth) colorStyle.borderWidth = borderWidth;
126→  if (borderStyle) colorStyle.borderStyle = borderStyle;
127→
128→  return (
129→    <>
130→      <NodeResizer
131→        isVisible={!isComponentChild && !!selected}
132→        minWidth={60}
133→        minHeight={30}
134→        lineClassName="!border-primary"
135→        handleClassName="!w-2 !h-2 !bg-primary !border-primary"
136→        onResizeStart={onResizeStart}
137→        onResize={onResize}
138→        onResizeEnd={onResizeEnd}
139→      />
140→      <div
141→        className={`relative flex w-full h-full ${
142→          textVerticalAlign === "top" ? "items-start" : textVerticalAlign === "bottom" ? "items-end" : "items-center"
143→        } ${
144→          textAlign === "left" ? "justify-start" : textAlign === "right" ? "justify-end" : "justify-center"
145→        } ${className}`}
146→        style={{ ...style, ...colorStyle }}
147→        onMouseEnter={() => setHovered(true)}
148→        onMouseLeave={() => setHovered(false)}
149→      >
150→        {positions.map((pos) => {
151→          if (ghostTargetHandle && `${pos}-target` !== ghostTargetHandle) return null;
152→          return <ConnectHandle key={`target-${pos}`} pos={pos} type="target" visible={isComponentChild ? false : visible} connectable={!isComponentChild} nodeId={id} />;
153→        })}
154→        {!ghostTargetHandle && isLocked && (
155→          <span className="absolute top-1 right-2 text-amber-500 dark:text-yellow-400" title="Locked">
156→            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
157→              <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
158→              <path d="M7 11V7a5 5 0 0 1 10 0v4" />
159→            </svg>
160→          </span>
161→        )}
162→        <NodeLabel
163→          id={id}
164→          label={label}
165→          fontSize={fontSize}
166→          textColor={computedText}
167→          textAlign={textAlign}
168→          bold={bold}
169→          italic={italic}
170→          underline={underline}
171→          isLocked={isLocked}
172→        />
173→        {positions.map((pos) => {
174→          if (ghostTargetHandle) return null; // ghost only needs target handle
175→          return <ConnectHandle key={`source-${pos}`} pos={pos} type="source" visible={isComponentChild ? false : visible} connectable={!isComponentChild} nodeId={id} />;
176→        })}
177→      </div>
178→    </>
179→  );
180→});
181→

 1→"use client";
 2→
 3→import { memo } from "react";
 4→import type { NodeProps } from "@xyflow/react";
 5→import { NodeWrapper } from "./NodeWrapper";
 6→import type { FlowNode } from "@/store/types";
 7→
 8→export const RectangleNode = memo(function RectangleNode({ id, data, selected }: NodeProps<FlowNode>) {
 9→  return (
10→    <NodeWrapper
11→      id={id}
12→      label={data.label}
13→      selected={selected}
14→      fillColor={data.fillColor}
15→      fillOpacity={data.fillOpacity}
16→      fillLightness={data.fillLightness}
17→      borderColor={data.borderColor}
18→      borderOpacity={data.borderOpacity}
19→      borderLightness={data.borderLightness}
20→      borderWidth={data.borderWidth}
21→      borderStyle={data.borderStyle}
22→      fontSize={data.fontSize}
23→      textColor={data.textColor}
24→      textOpacity={data.textOpacity}
25→      textLightness={data.textLightness}
26→      textAlign={data.textAlign}
27→      textVerticalAlign={data.textVerticalAlign}
28→      bold={data.bold}
29→      italic={data.italic}
30→      underline={data.underline}
31→      isLocked={data.isLocked}
32→      isComponentChild={!!data.componentParentId}
33→      ghostTargetHandle={data.ghostTargetHandle as string | undefined}
34→      className="bg-background border-2 border-muted-foreground px-4 py-2"
35→    />
36→  );
37→});
