114→      markerStart: markerStyleToMarker(e.markerStart, e.strokeColor),
115→      data: {
116→        label: e.label ?? "",
117→        edgeType: (e.edgeType ?? "bezier") as EdgeType,
118→        markerStart: e.markerStart,
119→        markerEnd: e.markerEnd ?? ("arrowclosed" as const),
120→        ...(e.strokeWidth ? { strokeWidth: e.strokeWidth } : {}),
121→        ...(e.strokeColor ? { strokeColor: e.strokeColor } : {}),
122→        ...(e.strokeOpacity !== undefined ? { strokeOpacity: e.strokeOpacity } : {}),
123→        ...(e.strokeLightness !== undefined ? { strokeLightness: e.strokeLightness } : {}),
