244→export function getEntryExitConnections(def: ComponentDefinition): {
245→  entryTargets: { nodeId: string; edgeProps: ComponentInternalEdge }[];
246→  exitSources: { nodeId: string; edgeProps: ComponentInternalEdge }[];
247→} {
248→  const entryTargets: { nodeId: string; edgeProps: ComponentInternalEdge }[] = [];
249→  const exitSources: { nodeId: string; edgeProps: ComponentInternalEdge }[] = [];
250→
251→  for (const e of def.edges) {
252→    if (def.entryNodeId && e.source === def.entryNodeId) {
253→      entryTargets.push({ nodeId: e.target, edgeProps: e });
254→    }
255→    if (def.exitNodeId && e.target === def.exitNodeId) {
256→      exitSources.push({ nodeId: e.source, edgeProps: e });
257→    }
258→  }
259→
260→  return { entryTargets, exitSources };
261→}
