 2→
 3→/**
 4→ * Track whether the Shift key is currently pressed.
 5→ * Shared across components via a module-level listener (only one pair of
 6→ * keydown/keyup listeners is registered regardless of how many components
 7→ * call this hook).
 8→ */
 9→
10→let listenerCount = 0;
11→let pressed = false;
12→const listeners = new Set<(v: boolean) => void>();
13→
14→function onKey(e: KeyboardEvent) {
15→  const next = e.shiftKey;
16→  if (next !== pressed) {
17→    pressed = next;
18→    for (const fn of listeners) fn(next);
19→  }
20→}
21→
22→function subscribe(fn: (v: boolean) => void) {
23→  listeners.add(fn);
24→  if (listenerCount === 0) {
25→    window.addEventListener("keydown", onKey);
26→    window.addEventListener("keyup", onKey);
27→  }
28→  listenerCount++;
29→  return () => {
30→    listeners.delete(fn);
31→    listenerCount--;
32→    if (listenerCount === 0) {
33→      window.removeEventListener("keydown", onKey);
34→      window.removeEventListener("keyup", onKey);
35→      pressed = false;
36→    }
37→  };
38→}
39→
40→export function useShiftKey(): boolean {
41→  const [shift, setShift] = useState(pressed);
42→  useEffect(() => subscribe(setShift), []);
43→  return shift;
44→}
