  1→"use client";
  2→
  3→import { useCallback, useRef, useState } from "react";
  4→import type { NodeChange, NodePositionChange } from "@xyflow/react";
  5→import type { FlowNode } from "@/store/types";
  6→
  7→export interface GuideLine {
  8→  orientation: "horizontal" | "vertical";
  9→  pos: number; // x for vertical, y for horizontal
 10→  from: number;
 11→  to: number;
 12→}
 13→
 14→const SNAP_THRESHOLD = 5;
 15→
 16→function getNodeBounds(node: FlowNode) {
 17→  const w = node.measured?.width ?? (node.style as Record<string, number>)?.width ?? 100;
 18→  const h = node.measured?.height ?? (node.style as Record<string, number>)?.height ?? 50;
 19→  return {
 20→    left: node.position.x,
 21→    centerX: node.position.x + w / 2,
 22→    right: node.position.x + w,
 23→    top: node.position.y,
 24→    centerY: node.position.y + h / 2,
 25→    bottom: node.position.y + h,
 26→    width: w,
 27→    height: h,
 28→  };
 29→}
 30→
 31→export function useSnapGuides(nodes: FlowNode[]) {
 32→  const [guides, setGuides] = useState<GuideLine[]>([]);
 33→  const nodesRef = useRef(nodes);
 34→  nodesRef.current = nodes;
 35→
 36→  const onNodeDrag = useCallback(
 37→    (_event: React.MouseEvent, dragNode: FlowNode) => {
 38→      const dragBounds = getNodeBounds(dragNode);
 39→      const newGuides: GuideLine[] = [];
 40→
 41→      const otherNodes = nodesRef.current.filter((n) => !n.selected && n.id !== dragNode.id);
 42→
 43→      for (const other of otherNodes) {
 44→        const ob = getNodeBounds(other);
 45→
 46→        // Vertical guides (X axis alignment)
 47→        const xChecks: { drag: number; ref: number }[] = [
 48→          { drag: dragBounds.left, ref: ob.left },
 49→          { drag: dragBounds.left, ref: ob.centerX },
 50→          { drag: dragBounds.left, ref: ob.right },
 51→          { drag: dragBounds.centerX, ref: ob.left },
 52→          { drag: dragBounds.centerX, ref: ob.centerX },
 53→          { drag: dragBounds.centerX, ref: ob.right },
 54→          { drag: dragBounds.right, ref: ob.left },
 55→          { drag: dragBounds.right, ref: ob.centerX },
 56→          { drag: dragBounds.right, ref: ob.right },
 57→        ];
 58→
 59→        for (const { drag, ref } of xChecks) {
 60→          if (Math.abs(drag - ref) < SNAP_THRESHOLD) {
 61→            const minY = Math.min(dragBounds.top, ob.top);
 62→            const maxY = Math.max(dragBounds.bottom, ob.bottom);
 63→            newGuides.push({ orientation: "vertical", pos: ref, from: minY, to: maxY });
 64→          }
 65→        }
 66→
 67→        // Horizontal guides (Y axis alignment)
 68→        const yChecks: { drag: number; ref: number }[] = [
 69→          { drag: dragBounds.top, ref: ob.top },
 70→          { drag: dragBounds.top, ref: ob.centerY },
 71→          { drag: dragBounds.top, ref: ob.bottom },
 72→          { drag: dragBounds.centerY, ref: ob.top },
 73→          { drag: dragBounds.centerY, ref: ob.centerY },
 74→          { drag: dragBounds.centerY, ref: ob.bottom },
 75→          { drag: dragBounds.bottom, ref: ob.top },
 76→          { drag: dragBounds.bottom, ref: ob.centerY },
 77→          { drag: dragBounds.bottom, ref: ob.bottom },
 78→        ];
 79→
 80→        for (const { drag, ref } of yChecks) {
 81→          if (Math.abs(drag - ref) < SNAP_THRESHOLD) {
 82→            const minX = Math.min(dragBounds.left, ob.left);
 83→            const maxX = Math.max(dragBounds.right, ob.right);
 84→            newGuides.push({ orientation: "horizontal", pos: ref, from: minX, to: maxX });
 85→          }
 86→        }
 87→      }
 88→
 89→      setGuides(newGuides);
 90→    },
 91→    []
 92→  );
 93→
 94→  const applySnap = useCallback(
 95→    (changes: NodeChange<FlowNode>[]): NodeChange<FlowNode>[] => {
 96→      const currentNodes = nodesRef.current;
 97→      return changes.map((change) => {
 98→        if (change.type !== "position" || !change.position) return change;
 99→
100→        const posChange = change as NodePositionChange;
101→        const node = currentNodes.find((n) => n.id === posChange.id);
102→        if (!node) return change;
103→
104→        const w = node.measured?.width ?? (node.style as Record<string, number>)?.width ?? 100;
105→        const h = node.measured?.height ?? (node.style as Record<string, number>)?.height ?? 50;
106→
107→        const GRID = 5;
108→        let x = Math.round(posChange.position!.x / GRID) * GRID;
109→        let y = Math.round(posChange.position!.y / GRID) * GRID;
110→        const otherNodes = currentNodes.filter((n) => !n.selected && n.id !== posChange.id);
111→
112→        // Snap X
113→        let snappedX = false;
114→        for (const other of otherNodes) {
115→          if (snappedX) break;
116→          const ob = getNodeBounds(other);
117→          const dragXs = [x, x + w / 2, x + w];
118→          const refXs = [ob.left, ob.centerX, ob.right];
119→          for (const dx of dragXs) {
120→            if (snappedX) break;
121→            for (const rx of refXs) {
122→              if (Math.abs(dx - rx) < SNAP_THRESHOLD) {
123→                x = x + (rx - dx);
124→                snappedX = true;
125→                break;
126→              }
127→            }
128→          }
129→        }
130→
131→        // Snap Y
132→        let snappedY = false;
133→        for (const other of otherNodes) {
134→          if (snappedY) break;
135→          const ob = getNodeBounds(other);
136→          const dragYs = [y, y + h / 2, y + h];
137→          const refYs = [ob.top, ob.centerY, ob.bottom];
138→          for (const dy of dragYs) {
139→            if (snappedY) break;
140→            for (const ry of refYs) {
141→              if (Math.abs(dy - ry) < SNAP_THRESHOLD) {
142→                y = y + (ry - dy);
143→                snappedY = true;
144→                break;
145→              }
146→            }
147→          }
148→        }
149→
150→        return { ...change, position: { x, y } } as NodeChange<FlowNode>;
151→      });
152→    },
153→    []
154→  );
155→
156→  const clearGuides = useCallback(() => {
157→    setGuides([]);
158→  }, []);
159→
160→  return { guides, onNodeDrag, applySnap, clearGuides };
161→}
