106→
107→  // Predictive input: compute all valid ghost nodes for all directions
108→  const addNodeWithData = useFlowStore((s) => s.addNodeWithData);
109→  const DIRECTIONS: PredictiveDirection[] = useMemo(() => ["top", "right", "bottom", "left"], []);
110→  const OVERLAP_MARGIN = 10;
111→
112→  // Global candidate index for Tab cycling (applies to all visible ghosts)
113→  const [ghostCandidateIndex, setGhostCandidateIndex] = useState(0);
114→
115→  // Cache candidates per source node (for Tab cycling)
116→  const candidatesMap = useMemo(() => {
117→    const map: Record<string, ReturnType<typeof computeCandidates>> = {};
118→    for (const node of nodes) {
119→      if (node.id.startsWith(GHOST_NODE_ID)) continue;
120→      if (node.data.componentParentId) continue;
121→      map[node.id] = computeCandidates(node, edges, nodes);
122→    }
123→    return map;
124→  }, [nodes, edges]);
