126→  const allGhosts = useMemo(() => {
127→    const ghostNodes: FlowNode[] = [];
128→    const ghostEdges: FlowEdge[] = [];
129→
130→    // Show ghosts only when exactly one node is selected (exclude text nodes — used as memos)
131→    const selectedNodes = nodes.filter((n) => n.selected && !n.id.startsWith(GHOST_NODE_ID) && !n.data.componentParentId && n.data.shape !== "text");
132→    const selectedNode = selectedNodes.length === 1 ? selectedNodes[0] : undefined;
133→    if (selectedNode) {
134→      const node = selectedNode;
135→      const candidates = candidatesMap[node.id];
136→      if (!candidates || candidates.length === 0) return { ghostNodes, ghostEdges };
137→
138→      for (const dir of DIRECTIONS) {
139→        // Component instances: only show ghosts in the component's flow direction
140→        if (node.data.componentDefinitionId) {
141→          const compDir = (node.data.componentDefinitionDirection as string) ?? "TD";
142→          if (compDir === "TD" && (dir === "left" || dir === "right")) continue;
143→          if (compDir === "LR" && (dir === "top" || dir === "bottom")) continue;
144→        }
145→
146→        // Pick candidate: use global cycled index for all ghosts
147→        const ghostKey = `${node.id}_${dir}`;
148→        const candIdx = ((ghostCandidateIndex % candidates.length) + candidates.length) % candidates.length;
149→        const candidate = candidates[candIdx];
150→
151→        // Skip if edge already connected in this direction
152→        const hasEdge = edges.some((e) => {
153→          if (e.data?.isBridgeEdge) return false;
154→          return (e.source === node.id && e.sourceHandle === `${dir}-source`) ||
155→                 (e.target === node.id && e.targetHandle === `${dir}-target`);
156→        });
157→        if (hasEdge) continue;
158→
159→        // Compute ghost position
160→        const ghostPos = computeGhostPosition(node, dir, candidate.nodeData.shape);
161→
162→        // Skip if overlapping existing node
163→        const hasOverlap = nodes.some((other) => {
164→          if (other.id === node.id || other.id.startsWith(GHOST_NODE_ID)) return false;
165→          if (other.data.componentParentId) return false;
166→          const ow = other.measured?.width ?? (other.style as Record<string, number>)?.width ?? DEFAULT_NODE_WIDTH;
167→          const oh = other.measured?.height ?? (other.style as Record<string, number>)?.height ?? DEFAULT_NODE_HEIGHT;
168→          return ghostPos.x < other.position.x + ow - OVERLAP_MARGIN &&
169→                 ghostPos.x + ghostPos.gw > other.position.x + OVERLAP_MARGIN &&
170→                 ghostPos.y < other.position.y + oh - OVERLAP_MARGIN &&
171→                 ghostPos.y + ghostPos.gh > other.position.y + OVERLAP_MARGIN;
172→        });
173→        if (hasOverlap) continue;
174→
175→        const ghostId = `${GHOST_NODE_ID}${ghostKey}`;
176→        const handles = DIRECTION_HANDLES[dir];
177→        const ghostSize = getDefaultSize(candidate.nodeData.shape);
178→
179→        ghostNodes.push({
180→          id: ghostId,
181→          type: candidate.nodeData.shape,
182→          position: { x: ghostPos.x, y: ghostPos.y },
183→          data: {
184→            ...candidate.nodeData,
185→            label: "...",
186→            ghostTargetHandle: handles.targetHandle,
187→            ghostSourceNodeId: node.id,
188→            ghostDirection: dir,
189→            ghostCandidateIndex: candIdx,
190→          },
191→          style: { width: ghostSize.width, height: ghostSize.height },
192→          selectable: false,
193→          draggable: false,
194→        });
195→
196→        ghostEdges.push({
197→          id: `__ghost_edge__${ghostKey}`,
198→          source: node.id,
199→          target: ghostId,
200→          sourceHandle: handles.sourceHandle,
201→          targetHandle: handles.targetHandle,
202→          type: "labeled",
203→          style: { strokeDasharray: "6 3" },
204→          selectable: false,
205→          markerEnd: { type: MarkerType.ArrowClosed },
206→          data: {
207→            edgeType: candidate.edgeData?.edgeType ?? "bezier",
208→            markerEnd: candidate.edgeData?.markerEnd ?? "arrowclosed",
209→            markerStart: candidate.edgeData?.markerStart,
210→            strokeStyle: "dashed",
211→          },
212→        } as FlowEdge);
213→      }
214→    }
215→
216→    return { ghostNodes, ghostEdges };
217→  }, [nodes, edges, DIRECTIONS, OVERLAP_MARGIN, candidatesMap, ghostCandidateIndex]);
218→
219→  const hasGhosts = allGhosts.ghostNodes.length > 0;
220→
221→  // Inject ghost nodes/edges into arrays for rendering
222→  const nodesWithGhost = useMemo(
