249→  // Track edge reconnection initiated from ring handles
250→  const reconnectingEdgeRef = useRef<FlowEdge | null>(null);
251→  const reconnectingTypeRef = useRef<"source" | "target" | null>(null);
252→
253→  const setEdgeVisibility = useCallback((edgeId: string | null, hidden: boolean) => {
254→    if (!edgeId) return;
255→    const edgeEl = document.querySelector(`.react-flow__edge[data-id="${CSS.escape(edgeId)}"]`);
256→    if (hidden) {
