263→  const onConnectStart = useCallback(
264→    (_event: MouseEvent | TouchEvent, params: { nodeId: string | null; handleId: string | null; handleType: "source" | "target" | null }) => {
265→      if (!params.nodeId || !params.handleId || !params.handleType) return;
266→      const currentEdges = useFlowStore.getState().edges;
267→      // Reconnect priority:
268→      // 1. Selected edge at this position (same pos, either source or target handle) → always reconnect
269→      //    Handles at the same position overlap visually, so user may grab the "wrong" one
270→      // 2. Exactly one edge on the dragged handle → reconnect it
271→      // 3. Multiple edges on handle + one selected → reconnect the selected one
272→      // 4. Otherwise → new connection mode
273→      const handlePos = params.handleId.split("-")[0]; // e.g. "bottom" from "bottom-source"
274→      const sourceHandleId = `${handlePos}-source`;
275→      const targetHandleId = `${handlePos}-target`;
276→
277→      // Priority 1: selected edge at this position (check both source and target handles)
278→      const selectedAtPos = currentEdges.find((e) => {
279→        if (!e.selected || e.data?.isBridgeEdge) return false;
280→        return (e.source === params.nodeId && e.sourceHandle === sourceHandleId) ||
281→               (e.target === params.nodeId && e.targetHandle === targetHandleId);
282→      });
283→
284→      let connectedEdge: FlowEdge | undefined;
285→      let actualReconnectType: "source" | "target" | null = null;
286→
287→      if (selectedAtPos) {
288→        connectedEdge = selectedAtPos;
289→        // Determine which side of the edge connects to this node at this position
290→        actualReconnectType = (selectedAtPos.source === params.nodeId && selectedAtPos.sourceHandle === sourceHandleId)
291→          ? "source" : "target";
292→      } else {
293→        // Priority 2-3: fall back to edges on the exact dragged handle
294→        const edgesOnHandle = currentEdges.filter((e) => {
295→          if (e.data?.isBridgeEdge) return false;
296→          if (params.handleType === "source") return e.source === params.nodeId && e.sourceHandle === params.handleId;
297→          return e.target === params.nodeId && e.targetHandle === params.handleId;
298→        });
299→        connectedEdge = edgesOnHandle.length === 1
300→          ? edgesOnHandle[0]
301→          : edgesOnHandle.find((e) => e.selected);
302→        actualReconnectType = connectedEdge ? params.handleType : null;
303→      }
304→
305→      reconnectingEdgeRef.current = connectedEdge ?? null;
306→      reconnectingTypeRef.current = actualReconnectType;
307→      reconnectFixedEnd = null;
308→      if (connectedEdge && actualReconnectType) {
309→        setEdgeVisibility(connectedEdge.id, true);
310→        // Calculate the FIXED endpoint (the end NOT being dragged) for connection line rendering
311→        const fixedType = actualReconnectType === "source" ? "target" : "source";
312→        const fixedNodeId = fixedType === "source" ? connectedEdge.source : connectedEdge.target;
313→        const fixedHandleId = fixedType === "source" ? connectedEdge.sourceHandle : connectedEdge.targetHandle;
314→        if (fixedNodeId && fixedHandleId && reactFlowInstance.current) {
315→          const handleEl = document.querySelector(
316→            `.react-flow__node[data-id="${CSS.escape(fixedNodeId)}"] .react-flow__handle[data-handleid="${CSS.escape(fixedHandleId)}"]`
317→          );
318→          if (handleEl) {
319→            const rect = handleEl.getBoundingClientRect();
320→            const pos = reactFlowInstance.current.screenToFlowPosition({
321→              x: rect.x + rect.width / 2,
322→              y: rect.y + rect.height / 2,
323→            });
324→            // Determine the Position enum from handle ID (e.g. "top-source" → Position.Top)
325→            const posStr = fixedHandleId.split("-")[0] as "top" | "right" | "bottom" | "left";
326→            const posMap: Record<string, import("@xyflow/react").Position> = {
327→              top: Position.Top, right: Position.Right, bottom: Position.Bottom, left: Position.Left,
328→            };
329→            reconnectFixedEnd = { x: pos.x, y: pos.y, position: posMap[posStr] ?? Position.Top };
