332→      }
333→    },
334→    [setEdgeVisibility]
335→  );
336→
337→  const onConnect = useCallback(
338→    (connection: Connection) => {
339→      if (!connection.source || !connection.target) return;
340→      // Ignore connections to/from ghost nodes (predictive input previews)
341→      if (connection.source.startsWith(GHOST_NODE_ID) || connection.target.startsWith(GHOST_NODE_ID)) return;
342→      const oldEdge = reconnectingEdgeRef.current;
343→      const reconnectType = reconnectingTypeRef.current;
344→      if (oldEdge && reconnectType) {
345→        // Determine which node in the connection is the new drop target
346→        const origNodeId = reconnectType === "source" ? oldEdge.source : oldEdge.target;
347→        const oldHandleId = reconnectType === "source" ? oldEdge.sourceHandle : oldEdge.targetHandle;
348→
349→        let newNodeId: string;
350→        let newHandle: string | null;
351→
352→        if (connection.source === connection.target) {
353→          // Same node: pick the handle that differs from the original
354→          newNodeId = connection.source!;
355→          const candidate = [connection.sourceHandle, connection.targetHandle].find(h => h && h !== oldHandleId);
356→          newHandle = candidate ?? null;
357→        } else {
358→          newNodeId = connection.source === origNodeId ? connection.target! : connection.source!;
359→          newHandle = connection.source === origNodeId ? connection.targetHandle : connection.sourceHandle;
360→        }
361→
362→        // Normalize handle ID suffix: React Flow may swap source/target in the connection object,
363→        // so the handle ID might have the wrong type suffix (e.g. "top-source" when we need "top-target")
364→        if (newHandle) {
365→          const pos = newHandle.split("-")[0];
366→          newHandle = `${pos}-${reconnectType}`;
367→        }
368→
369→        // Guard: if no valid handle found, abort reconnection
370→        if (!newHandle) return;
371→
372→        const newConnection: Connection = reconnectType === "source"
373→          ? { source: newNodeId, sourceHandle: newHandle, target: oldEdge.target, targetHandle: oldEdge.targetHandle ?? null }
374→          : { source: oldEdge.source, sourceHandle: oldEdge.sourceHandle ?? null, target: newNodeId, targetHandle: newHandle };
375→
376→        reconnectEdge(oldEdge, newConnection);
377→        setEdgeVisibility(oldEdge.id, false);
378→        reconnectingEdgeRef.current = null;
379→        reconnectingTypeRef.current = null;
380→        reconnectFixedEnd = null;
381→      } else {
382→        // Normalize handle IDs: React Flow may swap source/target when dragging from a target handle,
383→        // causing sourceHandle to have "-target" suffix and vice versa
384→        let srcHandle = connection.sourceHandle;
385→        let tgtHandle = connection.targetHandle;
386→        if (srcHandle) {
387→          const pos = srcHandle.split("-")[0];
388→          srcHandle = `${pos}-source`;
389→        }
390→        if (tgtHandle) {
391→          const pos = tgtHandle.split("-")[0];
392→          tgtHandle = `${pos}-target`;
393→        }
394→        addEdge(
395→          connection.source,
396→          connection.target,
397→          undefined,
398→          srcHandle,
399→          tgtHandle,
400→        );
401→      }
402→    },
403→    [addEdge, reconnectEdge, setEdgeVisibility]
404→  );
