451→  // --- Shared Ctrl+click / Ctrl+drag selection logic ---
452→  const {
453→    handleNodeClick,
454→    handleEdgeClick,
455→    handleSelectionStart: onSelectionStart,
456→    handleSelectionEnd: onSelectionEnd,
457→    processNodesChanges,
458→    processEdgesChanges,
