461→      const state = useFlowStore.getState();
462→      const ids = new Set<string>();
463→      for (const n of state.nodes) { if (n.selected) ids.add(n.id); }
464→      for (const e of state.edges) { if (e.selected) ids.add(e.id); }
465→      return ids;
466→    },
467→    setSelectedIds: (ids) => {
468→      const t = perfStart("setSelectedIds");
469→      const state = useFlowStore.getState();
470→      let nodesChanged = false;
471→      const nextNodes = state.nodes.map((n) => {
472→        const shouldSelect = ids.has(n.id);
473→        if (n.selected === shouldSelect) return n;
474→        nodesChanged = true;
475→        return { ...n, selected: shouldSelect };
476→      });
477→      let edgesChanged = false;
478→      const nextEdges = state.edges.map((e) => {
479→        const shouldSelect = ids.has(e.id);
480→        if (e.selected === shouldSelect) return e;
481→        edgesChanged = true;
482→        return { ...e, selected: shouldSelect };
483→      });
484→      if (nodesChanged || edgesChanged) {
