498→  const onNodesChangeWithSnap = useCallback(
499→    (changes: Parameters<typeof onNodesChange>[0]) => {
500→      const t = perfStart("onNodesChangeWithSnap");
501→      // Filter out changes targeting ghost nodes
502→      const filtered = changes.filter((c) => !("id" in c && typeof c.id === "string" && c.id.startsWith(GHOST_NODE_ID)));
503→      const remaining = processNodesChanges(filtered);
504→      if (remaining.length > 0) {
505→        onNodesChange(applySnap(remaining));
506→      }
507→      perfEnd("onNodesChangeWithSnap", t);
508→    },
509→    [onNodesChange, applySnap, processNodesChanges]
510→  );
511→
512→  const onEdgesChangeWithSelection = useCallback(
513→    (changes: Parameters<typeof onEdgesChange>[0]) => {
514→      // Filter out changes targeting ghost edges
515→      const filtered = changes.filter((c) => !("id" in c && typeof c.id === "string" && c.id.startsWith("__ghost_edge__")));
516→      const remaining = processEdgesChanges(filtered);
517→      if (remaining.length > 0) {
