    >
      <ChevronLeft size={14} className="text-muted-foreground" />
      <span
        className="text-[10px] text-muted-foreground"
        style={{ writingMode: "vertical-rl", textOrientation: "mixed" }}
      >
        Output
      </span>
    </button>
  );
}

