11→export const AUTOSAVE_DEBOUNCE_MS = 1000;
12→
13→// Predictive input
14→export const PREDICTIVE_DETECT_RANGE = 40;
15→export const PREDICTIVE_ARROW_OFFSET_PX = 28;
16→export const PREDICTIVE_GAP_PX = 60;
17→export const GHOST_NODE_ID = "__ghost__";
18→export const SNAP_GRID_SIZE = 5;
19→export const GRID_SNAP_SIZE = 20;
20→export const GRID_SNAP_STORAGE_KEY = "flowmaid-grid-snap";
21→
22→export const NODE_SHAPE_LABELS: Record<string, string> = {
23→  rectangle: "Rectangle",
24→  diamond: "Diamond",
25→  roundedRect: "Rounded Rect",
26→  circle: "Circle",
27→  parallelogram: "Parallelogram",
28→  cylinder: "Cylinder",
29→  hexagon: "Hexagon",
30→  stadium: "Stadium",
31→  trapezoid: "Trapezoid",
32→  document: "Document",
