      const currentNodes = nodesRef.current;
      const grid = gridSnapRef.current ? GRID_SNAP_SIZE : SNAP_GRID_SIZE;
      const otherNodes = currentNodes.filter((n) => !n.selected && n.id !== nodeId);

      // Grid snap: round all 4 edges to grid
      let x = Math.round(params.x / grid) * grid;
      let y = Math.round(params.y / grid) * grid;
      let right = Math.round((params.x + params.width) / grid) * grid;
      let bottom = Math.round((params.y + params.height) / grid) * grid;

      const newGuides: GuideLine[] = [];

      // Alignment snap for each edge
      for (const other of otherNodes) {
        const ob = getNodeBounds(other);
        const refXs = [ob.left, ob.centerX, ob.right];
        const refYs = [ob.top, ob.centerY, ob.bottom];

        // Snap left edge
        for (const rx of refXs) {
          if (Math.abs(x - rx) < SNAP_THRESHOLD) {
            x = rx;
            newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
            break;
          }
        }
        // Snap right edge
        for (const rx of refXs) {
          if (Math.abs(right - rx) < SNAP_THRESHOLD) {
            right = rx;
            newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
            break;
          }
        }
        // Snap top edge
        for (const ry of refYs) {
          if (Math.abs(y - ry) < SNAP_THRESHOLD) {
            y = ry;
            newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
            break;
          }
        }
        // Snap bottom edge
        for (const ry of refYs) {
          if (Math.abs(bottom - ry) < SNAP_THRESHOLD) {
            bottom = ry;
            newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
            break;
          }
        }
      }

      setGuides(newGuides);
      return { x, y, width: right - x, height: bottom - y };
    },
    []
  );

  const clearGuides = useCallback(() => {
    setGuides([]);
  }, []);

  return { guides, onNodeDrag, applySnap, applyResizeSnap, clearGuides };
}

