"use client";

import { useCallback, useRef, useState } from "react";
import type { NodeChange, NodePositionChange } from "@xyflow/react";
import type { FlowNode } from "@/store/types";
import { SNAP_GRID_SIZE, GRID_SNAP_SIZE } from "@/lib/constants";

/** Shared ref for resize snap — set by useSnapGuides, consumed by NodeWrapper */
export type ResizeSnapFn = (nodeId: string, params: { x: number; y: number; width: number; height: number }) => { x: number; y: number; width: number; height: number };
export const resizeSnapRef: { current: ResizeSnapFn | null } = { current: null };
export const clearGuidesRef: { current: (() => void) | null } = { current: null };

export interface GuideLine {
  orientation: "horizontal" | "vertical";
  pos: number; // x for vertical, y for horizontal
  from: number;
  to: number;
}

const SNAP_THRESHOLD = 15;

function getNodeBounds(node: FlowNode) {
  const w = node.measured?.width ?? (node.style as Record<string, number>)?.width ?? 100;
  const h = node.measured?.height ?? (node.style as Record<string, number>)?.height ?? 50;
  return {
    left: node.position.x,
    centerX: node.position.x + w / 2,
    right: node.position.x + w,
    top: node.position.y,
    centerY: node.position.y + h / 2,
    bottom: node.position.y + h,
    width: w,
    height: h,
  };
}

export function useSnapGuides(nodes: FlowNode[], gridSnap = false) {
  const [guides, setGuides] = useState<GuideLine[]>([]);
  const nodesRef = useRef(nodes);
  nodesRef.current = nodes;

  const onNodeDrag = useCallback(
    (_event: React.MouseEvent, dragNode: FlowNode) => {
      const dragBounds = getNodeBounds(dragNode);
      const newGuides: GuideLine[] = [];

      const otherNodes = nodesRef.current.filter((n) => !n.selected && n.id !== dragNode.id);

      for (const other of otherNodes) {
        const ob = getNodeBounds(other);

        // Vertical guides (X axis alignment)
        const xChecks: { drag: number; ref: number }[] = [
          { drag: dragBounds.left, ref: ob.left },
          { drag: dragBounds.left, ref: ob.centerX },
          { drag: dragBounds.left, ref: ob.right },
          { drag: dragBounds.centerX, ref: ob.left },
          { drag: dragBounds.centerX, ref: ob.centerX },
          { drag: dragBounds.centerX, ref: ob.right },
          { drag: dragBounds.right, ref: ob.left },
          { drag: dragBounds.right, ref: ob.centerX },
          { drag: dragBounds.right, ref: ob.right },
        ];

        for (const { drag, ref } of xChecks) {
          if (Math.abs(drag - ref) < SNAP_THRESHOLD) {
            const minY = Math.min(dragBounds.top, ob.top);
            const maxY = Math.max(dragBounds.bottom, ob.bottom);
            newGuides.push({ orientation: "vertical", pos: ref, from: minY, to: maxY });
          }
        }

        // Horizontal guides (Y axis alignment)
        const yChecks: { drag: number; ref: number }[] = [
          { drag: dragBounds.top, ref: ob.top },
          { drag: dragBounds.top, ref: ob.centerY },
          { drag: dragBounds.top, ref: ob.bottom },
          { drag: dragBounds.centerY, ref: ob.top },
          { drag: dragBounds.centerY, ref: ob.centerY },
          { drag: dragBounds.centerY, ref: ob.bottom },
          { drag: dragBounds.bottom, ref: ob.top },
          { drag: dragBounds.bottom, ref: ob.centerY },
          { drag: dragBounds.bottom, ref: ob.bottom },
        ];

        for (const { drag, ref } of yChecks) {
          if (Math.abs(drag - ref) < SNAP_THRESHOLD) {
            const minX = Math.min(dragBounds.left, ob.left);
            const maxX = Math.max(dragBounds.right, ob.right);
            newGuides.push({ orientation: "horizontal", pos: ref, from: minX, to: maxX });
          }
        }
      }

      setGuides(newGuides);
    },
    []
  );

  const gridSnapRef = useRef(gridSnap);
  gridSnapRef.current = gridSnap;

  const applySnap = useCallback(
    (changes: NodeChange<FlowNode>[]): NodeChange<FlowNode>[] => {
      const currentNodes = nodesRef.current;
      const grid = gridSnapRef.current ? GRID_SNAP_SIZE : SNAP_GRID_SIZE;

      // Detect resize: find ids that have a "dimensions" change with resizing=true
      const resizeIds = new Set<string>();
      for (const c of changes) {
        if (c.type === "dimensions" && "resizing" in c && c.resizing) {
          resizeIds.add(c.id);
        }
      }

      // For each resize id, compute snapped {x, y, width, height} from the pair of changes
      const resizeSnapResults = new Map<string, { x: number; y: number; width: number; height: number }>();
      if (resizeIds.size > 0) {
        const newGuides: GuideLine[] = [];
        for (const id of resizeIds) {
          const node = currentNodes.find((n) => n.id === id);
          if (!node) continue;
          const posChange = changes.find(
            (c) => c.type === "position" && "id" in c && c.id === id && c.position
          ) as NodePositionChange | undefined;
          const dimChange = changes.find(
            (c) => c.type === "dimensions" && "id" in c && c.id === id && "dimensions" in c
          ) as Extract<NodeChange<FlowNode>, { type: "dimensions" }> | undefined;

          const startX = posChange?.position?.x ?? node.position.x;
          const startY = posChange?.position?.y ?? node.position.y;
          const startW = dimChange?.dimensions?.width
            ?? node.measured?.width
            ?? (node.style as Record<string, number>)?.width
            ?? 100;
          const startH = dimChange?.dimensions?.height
            ?? node.measured?.height
            ?? (node.style as Record<string, number>)?.height
            ?? 50;

          // Grid snap edges
          let x = Math.round(startX / grid) * grid;
          let y = Math.round(startY / grid) * grid;
          let right = Math.round((startX + startW) / grid) * grid;
          let bottom = Math.round((startY + startH) / grid) * grid;

          const otherNodes = currentNodes.filter((n) => n.id !== id && !n.data?.componentParentId);

          // Alignment snap for each edge against other nodes' edges
          for (const other of otherNodes) {
            const ob = getNodeBounds(other);
            const refXs = [ob.left, ob.centerX, ob.right];
            const refYs = [ob.top, ob.centerY, ob.bottom];

            for (const rx of refXs) {
              if (Math.abs(x - rx) < SNAP_THRESHOLD) {
                x = rx;
                newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
                break;
              }
            }
            for (const rx of refXs) {
              if (Math.abs(right - rx) < SNAP_THRESHOLD) {
                right = rx;
                newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
                break;
              }
            }
            for (const ry of refYs) {
              if (Math.abs(y - ry) < SNAP_THRESHOLD) {
                y = ry;
                newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
                break;
              }
            }
            for (const ry of refYs) {
              if (Math.abs(bottom - ry) < SNAP_THRESHOLD) {
                bottom = ry;
                newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
                break;
              }
            }
          }

          resizeSnapResults.set(id, { x, y, width: Math.max(grid, right - x), height: Math.max(grid, bottom - y) });
        }
        setGuides(newGuides);
      }

      return changes.map((change) => {
        // Resize: rewrite position/dimensions changes with snapped values
        if ("id" in change && resizeSnapResults.has(change.id)) {
          const r = resizeSnapResults.get(change.id)!;
          if (change.type === "position" && change.position) {
            return { ...change, position: { x: r.x, y: r.y } } as NodeChange<FlowNode>;
          }
          if (change.type === "dimensions" && "dimensions" in change && change.dimensions) {
            return { ...change, dimensions: { width: r.width, height: r.height } } as NodeChange<FlowNode>;
          }
          return change;
        }

        // Move (non-resize position change)
        if (change.type !== "position" || !change.position) return change;

        const posChange = change as NodePositionChange;
        const node = currentNodes.find((n) => n.id === posChange.id);
        if (!node) return change;

        const w = node.measured?.width ?? (node.style as Record<string, number>)?.width ?? 100;
        const h = node.measured?.height ?? (node.style as Record<string, number>)?.height ?? 50;

        let x = Math.round(posChange.position!.x / grid) * grid;
        let y = Math.round(posChange.position!.y / grid) * grid;
        const otherNodes = currentNodes.filter((n) => !n.selected && n.id !== posChange.id);

        // Snap X
        let snappedX = false;
        for (const other of otherNodes) {
          if (snappedX) break;
          const ob = getNodeBounds(other);
          const dragXs = [x, x + w / 2, x + w];
          const refXs = [ob.left, ob.centerX, ob.right];
          for (const dx of dragXs) {
            if (snappedX) break;
            for (const rx of refXs) {
              if (Math.abs(dx - rx) < SNAP_THRESHOLD) {
                x = x + (rx - dx);
                snappedX = true;
                break;
              }
            }
          }
        }

        // Snap Y
        let snappedY = false;
        for (const other of otherNodes) {
          if (snappedY) break;
          const ob = getNodeBounds(other);
          const dragYs = [y, y + h / 2, y + h];
          const refYs = [ob.top, ob.centerY, ob.bottom];
          for (const dy of dragYs) {
            if (snappedY) break;
            for (const ry of refYs) {
              if (Math.abs(dy - ry) < SNAP_THRESHOLD) {
                y = y + (ry - dy);
                snappedY = true;
                break;
              }
            }
          }
        }

        return { ...change, position: { x, y } } as NodeChange<FlowNode>;
      });
    },
    []
  );

  /** Snap resize params (x, y, width, height) to grid and/or other node edges.
   *  Returns adjusted params and updates guide lines. */
  const applyResizeSnap = useCallback(
    (nodeId: string, params: { x: number; y: number; width: number; height: number }) => {
      const currentNodes = nodesRef.current;
      const grid = gridSnapRef.current ? GRID_SNAP_SIZE : SNAP_GRID_SIZE;
      const otherNodes = currentNodes.filter((n) => !n.selected && n.id !== nodeId);

      // Grid snap: round all 4 edges to grid
      let x = Math.round(params.x / grid) * grid;
      let y = Math.round(params.y / grid) * grid;
      let right = Math.round((params.x + params.width) / grid) * grid;
      let bottom = Math.round((params.y + params.height) / grid) * grid;

      const newGuides: GuideLine[] = [];

      // Alignment snap for each edge
      for (const other of otherNodes) {
        const ob = getNodeBounds(other);
        const refXs = [ob.left, ob.centerX, ob.right];
        const refYs = [ob.top, ob.centerY, ob.bottom];

        // Snap left edge
        for (const rx of refXs) {
          if (Math.abs(x - rx) < SNAP_THRESHOLD) {
            x = rx;
            newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
            break;
          }
        }
        // Snap right edge
        for (const rx of refXs) {
          if (Math.abs(right - rx) < SNAP_THRESHOLD) {
            right = rx;
            newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
            break;
          }
        }
        // Snap top edge
        for (const ry of refYs) {
          if (Math.abs(y - ry) < SNAP_THRESHOLD) {
            y = ry;
            newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
            break;
          }
        }
        // Snap bottom edge
        for (const ry of refYs) {
          if (Math.abs(bottom - ry) < SNAP_THRESHOLD) {
            bottom = ry;
            newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
            break;
          }
        }
      }

      setGuides(newGuides);
      return { x, y, width: right - x, height: bottom - y };
    },
    []
  );

  const clearGuides = useCallback(() => {
    setGuides([]);
  }, []);

  // Expose via module-level refs for NodeWrapper consumption
  resizeSnapRef.current = applyResizeSnap;
  clearGuidesRef.current = clearGuides;

  return { guides, onNodeDrag, applySnap, applyResizeSnap, clearGuides };
}

