// Detect which edges are being dragged (the moving edges).
// If the original node.position.x equals startX, left edge is fixed → right edge is moving.
const leftMoving = startX !== node.position.x;
const topMoving = startY !== node.position.y;
const rightMoving = !leftMoving;
const bottomMoving = !topMoving;

// Grid snap edges
let x = Math.round(startX / grid) * grid;
let y = Math.round(startY / grid) * grid;
let right = Math.round((startX + startW) / grid) * grid;
let bottom = Math.round((startY + startH) / grid) * grid;

const otherNodes = currentNodes.filter((n) => n.id !== id && !n.data?.componentParentId);

// Alignment snap for each edge against other nodes' edges
for (const other of otherNodes) {
  const ob = getNodeBounds(other);
  const refXs = [ob.left, ob.centerX, ob.right];
  const refYs = [ob.top, ob.centerY, ob.bottom];

  for (const rx of refXs) {
    if (Math.abs(x - rx) < SNAP_THRESHOLD) {
      x = rx;
      newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
      break;
    }
  }
  for (const rx of refXs) {
    if (Math.abs(right - rx) < SNAP_THRESHOLD) {
      right = rx;
      newGuides.push({ orientation: "vertical", pos: rx, from: Math.min(y, ob.top), to: Math.max(bottom, ob.bottom) });
      break;
    }
  }
  for (const ry of refYs) {
    if (Math.abs(y - ry) < SNAP_THRESHOLD) {
      y = ry;
      newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
      break;
    }
  }
  for (const ry of refYs) {
    if (Math.abs(bottom - ry) < SNAP_THRESHOLD) {
      bottom = ry;
      newGuides.push({ orientation: "horizontal", pos: ry, from: Math.min(x, ob.left), to: Math.max(right, ob.right) });
      break;
    }
  }
}

// Equal-size snap: match width/height to other nodes' dimensions
// Adjust the moving edge so the dimension matches.
let curW = right - x;
let curH = bottom - y;
for (const other of otherNodes) {
  const ob = getNodeBounds(other);
  if (Math.abs(curW - ob.width) < SNAP_THRESHOLD) {
    if (rightMoving) {
      right = x + ob.width;
    } else if (leftMoving) {
      x = right - ob.width;
    }
    curW = ob.width;
    // Guide line spanning both nodes (top edges of each)
    newGuides.push({
      orientation: "horizontal",
      pos: Math.min(y, ob.top) - 8,
      from: Math.min(x, ob.left),
      to: Math.max(right, ob.right),
    });
    break;
  }
}
for (const other of otherNodes) {
  const ob = getNodeBounds(other);
  if (Math.abs(curH - ob.height) < SNAP_THRESHOLD) {
    if (bottomMoving) {
      bottom = y + ob.height;
    } else if (topMoving) {
      y = bottom - ob.height;
    }
    curH = ob.height;
    newGuides.push({
      orientation: "vertical",
      pos: Math.min(x, ob.left) - 8,
      from: Math.min(y, ob.top),
      to: Math.max(bottom, ob.bottom),
    });
    break;
  }
}

resizeSnapResults.set(id, { x, y, width: Math.max(grid, right - x), height: Math.max(grid, bottom - y) });

