                    x1={g.pos}
                    y1={g.from}
                    x2={g.pos}
                    y2={g.to}
                    stroke={COLOR}
                    strokeWidth={lineW}
                  />
                  <circle cx={g.pos} cy={g.from} r={dotR} fill={COLOR} />
                  <circle cx={g.pos} cy={g.to} r={dotR} fill={COLOR} />
                </g>
              );
            }
            return (
              <g key={i}>
                <line
                  x1={g.from}
                  y1={g.pos}
                  x2={g.to}
                  y2={g.pos}
                  stroke={COLOR}
                  strokeWidth={lineW}
                />
                <circle cx={g.from} cy={g.pos} r={dotR} fill={COLOR} />
                <circle cx={g.to} cy={g.pos} r={dotR} fill={COLOR} />
              </g>
            );
          }

          // size-match
          const { a, b, dimension, value } = g;
          if (dimension === "width") {
            // Highlight the top edge of both nodes (the matching dimension)
            // and draw a label between them
            const midY = (a.y + a.h / 2 + b.y + b.h / 2) / 2;
            const labelX = (Math.max(a.x, b.x) + Math.min(a.x + a.w, b.x + b.w)) / 2;
            const fontSize = 11 / scale;
            const padX = 4 / scale;
            const padY = 2 / scale;
            const labelText = `${Math.round(value)}`;
            const charW = fontSize * 0.6;
            const labelW = labelText.length * charW + padX * 2;
            const labelH = fontSize + padY * 2;
            return (
              <g key={i}>
                {/* Top edge of resizing node */}
                <line
                  x1={a.x}
                  y1={a.y}
                  x2={a.x + a.w}
                  y2={a.y}
                  stroke={COLOR}
                  strokeWidth={2 / scale}
                />
                {/* Top edge of matching node */}
                <line
                  x1={b.x}
                  y1={b.y}
                  x2={b.x + b.w}
                  y2={b.y}
                  stroke={COLOR}
                  strokeWidth={2 / scale}
                />
                {/* Label background */}
                <rect
                  x={labelX - labelW / 2}
                  y={midY - labelH / 2}
                  width={labelW}
                  height={labelH}
                  rx={2 / scale}
                  fill={COLOR}
                />
                <text
                  x={labelX}
                  y={midY + fontSize / 3}
                  fontSize={fontSize}
                  fill="white"
                  textAnchor="middle"
                  fontWeight="600"
                  fontFamily="system-ui, sans-serif"
                >
                  {labelText}
                </text>
              </g>
            );
          }

          // height match — highlight left edge of both nodes
          const midX = (a.x + a.w / 2 + b.x + b.w / 2) / 2;
          const labelY = (Math.max(a.y, b.y) + Math.min(a.y + a.h, b.y + b.h)) / 2;
          const fontSize = 11 / scale;
          const padX = 4 / scale;
          const padY = 2 / scale;
          const labelText = `${Math.round(value)}`;
          const charW = fontSize * 0.6;
          const labelW = labelText.length * charW + padX * 2;
          const labelH = fontSize + padY * 2;
          return (
            <g key={i}>
              <line
                x1={a.x}
                y1={a.y}
                x2={a.x}
                y2={a.y + a.h}
                stroke={COLOR}
                strokeWidth={2 / scale}
              />
              <line
                x1={b.x}
                y1={b.y}
                x2={b.x}
                y2={b.y + b.h}
                stroke={COLOR}
                strokeWidth={2 / scale}
              />
              <rect
                x={midX - labelW / 2}
                y={labelY - labelH / 2}
                width={labelW}
                height={labelH}
                rx={2 / scale}
                fill={COLOR}
              />
              <text
                x={midX}
                y={labelY + fontSize / 3}
                fontSize={fontSize}
                fill="white"
                textAnchor="middle"
                fontWeight="600"
                fontFamily="system-ui, sans-serif"
              >
                {labelText}
              </text>
            </g>
          );
        })}
      </g>
    </svg>
  );
}

