  const draggedRight = spacingX.x + dragBounds.width;
  const yLevel = (Math.max(spacingX.leftAnchor.top, spacingX.rightAnchor.top, dragBounds.top) +
    Math.min(spacingX.leftAnchor.bottom, spacingX.rightAnchor.bottom, dragBounds.bottom)) / 2;
  newGuides.push({
    kind: "spacing",
    axis: "horizontal",
    gap: spacingX.gap,
    pos: yLevel,
    segments: [
      { from: spacingX.leftAnchor.right, to: spacingX.x },
      { from: draggedRight, to: spacingX.rightAnchor.left },
    ],
  });
}
const spacingY = detectSpacingY(dragBounds.top, dragBounds.height, dragBounds.left, dragBounds.right, otherBounds);
if (spacingY) {
  const draggedBottom = spacingY.y + dragBounds.height;
  const xLevel = (Math.max(spacingY.topAnchor.left, spacingY.bottomAnchor.left, dragBounds.left) +
    Math.min(spacingY.topAnchor.right, spacingY.bottomAnchor.right, dragBounds.right)) / 2;
  newGuides.push({
    kind: "spacing",
    axis: "vertical",
    gap: spacingY.gap,
    pos: xLevel,
    segments: [
      { from: spacingY.topAnchor.bottom, to: spacingY.y },
      { from: draggedBottom, to: spacingY.bottomAnchor.top },
    ],
  });
}

setGuides(newGuides);

