        // Snap X
        let snappedX = false;
        for (const other of otherNodes) {
          if (snappedX) break;
          const ob = getNodeBounds(other);
          const dragXs = [x, x + w / 2, x + w];
          const refXs = [ob.left, ob.centerX, ob.right];
          for (const dx of dragXs) {
            if (snappedX) break;
            for (const rx of refXs) {
              if (Math.abs(dx - rx) < SNAP_THRESHOLD) {
                x = x + (rx - dx);
                snappedX = true;
                break;
              }
            }
          }
        }

