"use client";

import { useStore } from "@xyflow/react";
import type { GuideLine } from "@/hooks/useSnapGuides";

const COLOR = "#f97316";

export function SnapGuides({ guides }: { guides: GuideLine[] }) {
  const transform = useStore((s) => s.transform);

  if (guides.length === 0) return null;

  const [tx, ty, scale] = transform;
  const lineW = 1 / scale;
  const dotR = 3 / scale;

  return (
    <svg
      style={{
        position: "absolute",
        top: 0,
        left: 0,
        width: "100%",
        height: "100%",
        pointerEvents: "none",
        zIndex: 1000,
      }}
    >
      <g transform={`translate(${tx}, ${ty}) scale(${scale})`}>
        {guides.map((g, i) => {
          if (g.kind === "alignment") {
            // Short line with dot markers at both endpoints
            if (g.orientation === "vertical") {
              return (
                <g key={i}>
                  <line
                    x1={g.pos}
                    y1={g.from}
                    x2={g.pos}
                    y2={g.to}
                    stroke={COLOR}
                    strokeWidth={lineW}
                  />
                  <circle cx={g.pos} cy={g.from} r={dotR} fill={COLOR} />
                  <circle cx={g.pos} cy={g.to} r={dotR} fill={COLOR} />
                </g>
              );
            }
            return (
              <g key={i}>
                <line
                  x1={g.from}
                  y1={g.pos}
                  x2={g.to}
                  y2={g.pos}
                  stroke={COLOR}
                  strokeWidth={lineW}
                />
                <circle cx={g.from} cy={g.pos} r={dotR} fill={COLOR} />
                <circle cx={g.to} cy={g.pos} r={dotR} fill={COLOR} />
              </g>
            );
          }

          // size-match
          const { a, b, dimension, value } = g;
          const fontSize = 11 / scale;
          const padX = 4 / scale;
          const padY = 2 / scale;
          const labelText = `${Math.round(value)}`;
          const charW = fontSize * 0.6;
          const labelW = labelText.length * charW + padX * 2;
          const labelH = fontSize + padY * 2;
          const gap = 6 / scale;

          const renderLabel = (cx: number, cy: number) => (
            <>
              <rect
                x={cx - labelW / 2}
                y={cy - labelH / 2}
                width={labelW}
                height={labelH}
                rx={2 / scale}
                fill={COLOR}
              />
              <text
                x={cx}
                y={cy + fontSize / 3}
                fontSize={fontSize}
                fill="white"
                textAnchor="middle"
                fontWeight="600"
                fontFamily="system-ui, sans-serif"
              >
                {labelText}
              </text>
            </>
          );

          if (dimension === "width") {
            // Highlight top edge of both nodes; label above each top edge
            return (
              <g key={i}>
                <line x1={a.x} y1={a.y} x2={a.x + a.w} y2={a.y} stroke={COLOR} strokeWidth={2 / scale} />
                <line x1={b.x} y1={b.y} x2={b.x + b.w} y2={b.y} stroke={COLOR} strokeWidth={2 / scale} />
                {renderLabel(a.x + a.w / 2, a.y - gap - labelH / 2)}
                {renderLabel(b.x + b.w / 2, b.y - gap - labelH / 2)}
              </g>
            );
          }

          // height match — highlight left edge of both nodes; label to the left of each left edge
          return (
            <g key={i}>
              <line x1={a.x} y1={a.y} x2={a.x} y2={a.y + a.h} stroke={COLOR} strokeWidth={2 / scale} />
              <line x1={b.x} y1={b.y} x2={b.x} y2={b.y + b.h} stroke={COLOR} strokeWidth={2 / scale} />
              {renderLabel(a.x - gap - labelW / 2, a.y + a.h / 2)}
              {renderLabel(b.x - gap - labelW / 2, b.y + b.h / 2)}
            </g>
          );
        })}
      </g>
    </svg>
  );
}

